```plantuml
@startuml
interface HttpHandler <<external library>> <<interface>>

class PolicyModelHttpHandler <<abstract>> {
  - splitQuery(String query): Map<String, String>
  - getRequestBody(HttpExchange httpExchange): String
  + handle(HttpExchange httpExchange)
  + getRequestParams(HttpExchange httpExchange): Map<String, String>
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class LoadModelHandler {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class CreateNewLocalizationHandler {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class UpdateLocalizationHandler {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class VisualizePSHandler {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class VisualizeDGHandler {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class NewModelHandler {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class PolicyModelService {
}

class "jackson-annotations\njackson-core\njackson-databind" as Jackson <<external libraries>>

HttpHandler <|.. PolicyModelHttpHandler

PolicyModelHttpHandler <|-- LoadModelHandler
PolicyModelHttpHandler <|-- CreateNewLocalizationHandler
PolicyModelHttpHandler <|-- UpdateLocalizationHandler
PolicyModelHttpHandler <|-- VisualizePSHandler
PolicyModelHttpHandler <|-- VisualizeDGHandler
PolicyModelHttpHandler <|-- NewModelHandler

LoadModelHandler --> PolicyModelService : uses
CreateNewLocalizationHandler --> PolicyModelService : uses
UpdateLocalizationHandler --> PolicyModelService : uses
VisualizePSHandler --> PolicyModelService : uses
VisualizeDGHandler --> PolicyModelService : uses
NewModelHandler --> PolicyModelService : uses

NewModelHandler --> Jackson : uses

@enduml
```
